arguments.new_str:
protected override void OnModelCreating(ModelBuilder modelBuilder)
{
    modelBuilder.Entity<Product>(entity =>
    {
        entity.ToContainer("Products");

        // EF Core 9 renamed the default discriminator property from "Discriminator" to "$type".
        // Preserve the old name so existing 500K documents and direct SQL queries
        // (e.g., WHERE c.Discriminator = 'Product') continue to work.
        entity.HasDiscriminator<string>("Discriminator");

        // EF Core 9 no longer includes the discriminator in the JSON id property.
        // Preserve the old "Product|123" format so existing documents remain accessible.
        entity.HasRootDiscriminatorInJsonId(true);
    });
}

arguments.old_str:
class CosmosQuery
{
    void FindProducts(ProductContext ctx)
    {
        // Direct Cosmos SQL
        var sql = "SELECT * FROM c WHERE c.Discriminator = 'Product' AND c.Sku = @sku";
        // Also uses sync APIs
        var products = ctx.Products.Where(p => p.Sku == "ABC").ToList();
    }
}

arguments.new_str:
using System.Linq;

class CosmosQuery
{
    // EF Core 9 Cosmos provider no longer supports synchronous I/O.
    // All queries must use async equivalents (ToListAsync, SaveChangesAsync, etc.).
    async Task FindProducts(ProductContext ctx)
    {
        // Direct Cosmos SQL — safe because we explicitly configured
        // HasDiscriminator<string>("Discriminator") in ProductContext.
        var sql = "SELECT * FROM c WHERE c.Discriminator = 'Product' AND c.Sku = @sku";

        var products = await ctx.Products.Where(p => p.Sku == "ABC").ToListAsync();
    }
}

